query:
query GetAuthorFeed($contentSearchInput: ContentSearchInput!, $clientContext: ClientContext!, $count: Int!, $start: Int!, $authorImageTransforms: [MysterioTransformsInput]! = [], $imageTransforms: [MysterioTransformsInput]! = [], $includeImageTransforms: Boolean! = true) {
  authorStream: contentSearchStream(
    contentSearchInput: $contentSearchInput
    cc: $clientContext
    count: $count
    start: $start
  ) {
    author: asset {
      ... on Author {
        byline
        description
        displayName
        contactInfo {
          facebookId
          twitterId: xTwitterId
        }
        assetAttributes {
          images {
            type: imgType
            originalUrl: url
            originalHeight: height
            originalWidth: width
            resolutions: mysterioImages(transformInputs: $authorImageTransforms) @include(if: $includeImageTransforms) {
              ...Resolutions
            }
          }
        }
        __typename
      }
    }
    stream: assets {
      ...HydratedStoryOrVideoAsset
    }
    pagination {
      nextPage
      total
    }
  }
}
fragment Resolutions on MysterioImage {
  url
  height
  width
  transformLabel
}
fragment Image on Image {
  type: imgType
  originalUrl: url
  originalHeight: height
  originalWidth: width
  resolutions: mysterioImages(transformInputs: $imageTransforms) @include(if: $includeImageTransforms) {
    ...Resolutions
  }
}
fragment ContentAttributes on ContentAttributes {
  description
  summary
  pubDate: publishTime
  displayTime
  isHosted
  canonicalUrl
  clickthroughUrl
  provider {
    displayName
    url
    providerContentUrl
    providerId
  }
  thumbnail {
    ...Image
  }
  mabMeta {
    mabLogString
  }
}
fragment FinanceStockTickers on Finance {
  stockTickers {
    symbol
  }
}
fragment StoryData on Story {
  id: uuid
  __typename
  title
  previewUrl(cc: $clientContext)
  isPremiumNews
  isLiveBlog
  embeddedLiveBlog {
    status
  }
  contentAttributes {
    ...ContentAttributes
  }
  finance {
    ...FinanceStockTickers
  }
}
fragment VideoData on Video {
  id: uuid
  __typename
  title
  duration
  previewUrl(cc: $clientContext)
  liveEventInfo {
    scheduledStartTime
    scheduledStopTime
    status
  }
  contentAttributes {
    ...ContentAttributes
  }
  finance {
    ...FinanceStockTickers
  }
}
fragment OutlinkData on Outlink {
  __typename
  uuid
  description
  displayTime
  headline
  url
  provider {
    displayName
    url
    providerContentUrl
    providerId
  }
  thumbnail {
    ...Image
  }
}
fragment HydratedStoryOrVideoAsset on HydratedAsset {
  __typename
  asset {
    __typename
    ... on Story {
      ...StoryData
    }
    ... on Video {
      ...VideoData
    }
    ... on Outlink {
      ...OutlinkData
    }
  }
}
